import{_ as e,o,c as i,al as r}from"./chunks/framework.BdhqLO8e.js";const p=JSON.parse('{"title":"Contribute","description":"How to contribute to the Citizen skin.","frontmatter":{"title":"Contribute","description":"How to contribute to the Citizen skin."},"headers":[],"relativePath":"contribute/index.md","filePath":"contribute/index.md","lastUpdated":1764373935000}'),a={name:"contribute/index.md"};function n(s,t,l,u,c,h){return o(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="contribute" tabindex="-1">Contribute <a class="header-anchor" href="#contribute" aria-label="Permalink to &quot;Contribute&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Thank you for considering contributing to Citizen!</p><p>Citizen is a small open-source project, and we really appreciate any help from the community.</p></div><p>Here are a few ways you can get involved:</p><ul><li>✨ <strong>Code patches</strong>: Fix bugs or add new features.</li><li>📚 <strong>Documentation</strong>: Help us improve our guides and docs.</li><li>🐛 <strong>Bug reports</strong>: Found a glitch? Let us know!</li><li>💡 <strong>Suggestions</strong>: Have an idea for a cool new feature?</li><li>🌍 <strong>Translations</strong>: Help us bring Citizen to more languages.</li></ul><h2 id="code" tabindex="-1">Code <a class="header-anchor" href="#code" aria-label="Permalink to &quot;Code&quot;">​</a></h2><p>Ready to dive in? Follow these steps to contribute code:</p><ol><li>🍴 <strong>Fork</strong> the <a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/fork" target="_blank" rel="noreferrer">Citizen repository</a>.</li><li>🌿 <strong>Create a new branch</strong> in your fork to work on your changes.</li><li>💾 <strong>Commit</strong> your changes to your new branch.</li><li>⬆️ <strong>Push</strong> your changes to your fork on GitHub.</li><li>🔃 <strong>Submit a pull request</strong> from your branch to the main Citizen repository.</li></ol><p>We will review your pull request and, if everything looks good, merge it into the main codebase.</p><h2 id="translate" tabindex="-1">Translate <a class="header-anchor" href="#translate" aria-label="Permalink to &quot;Translate&quot;">​</a></h2><p>Want to see Citizen in your language? You can easily submit translations via <a href="https://translatewiki.net/w/i.php?title=Special:Translate&amp;group=mwgithub-star-citizen" target="_blank" rel="noreferrer">TranslateWiki.net</a>.</p><p>Changes are typically merged into the project bi-weekly.</p><h2 id="questions" tabindex="-1">Questions? <a class="header-anchor" href="#questions" aria-label="Permalink to &quot;Questions?&quot;">​</a></h2><p>Stuck? Have a question? We&#39;d love to hear from you!</p><p>Feel free to <a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/issues/new/choose" target="_blank" rel="noreferrer">open an issue</a> in the repository to ask questions or discuss ideas.</p><h2 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h2><a href="https://github.com/StarCitizenTools/mediawiki-skins-citizen/graphs/contributors"><img src="https://contrib.rocks/image?repo=StarCitizenTools/mediawiki-skins-citizen" alt="Citizen contributors" title="Citizen contributors" width="812px"></a>',16)])])}const g=e(a,[["render",n]]);export{p as __pageData,g as default};
